using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;/// <summary>/// Good case: Retrieve a specific version of an EHR record/// Expected: 200 OK with version details/// </summary>public class EhrServiceTests_GetEhrVersionById_WithValidIds_ShouldReturnVersion : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService"    };    [SkippableFact]    public async Task GetEhrVersionById_WithValidIds_ShouldReturnVersion()    {        await AuthenticateAsDoctorAsync(EhrClient);        // Step 1: Create an EHR record        var createRequest = new         {             patientId = TestSeedData.PatientUserId,             orgId = TestSeedData.HospitalAOrgId,             encounterId = Guid.NewGuid(),             data = new             {                 doctorId = TestSeedData.DoctorUserId,                 diagnosis = "Version test",                 treatment = "Test treatment",                 notes = "First version"             }         };        var createResponse = await PostAsJsonWithRetryAsync(EhrClient, ApiEndpoints.Ehr.CreateRecord, createRequest);        var createJson = await ReadJsonResponseAsync(createResponse);                if (!createJson.TryGetProperty("ehrId", out var ehrIdElement))            return; // Skip if creation fails        var ehrId = Guid.Parse(ehrIdElement.GetString()!);        // Step 2: Get all versions first to retrieve a versionId        var versionsResponse = await GetWithRetryAsync(EhrClient, ApiEndpoints.Ehr.Versions(ehrId));                if (versionsResponse.StatusCode != HttpStatusCode.OK)            return; // Skip if versions retrieval fails        var versionsJson = await ReadJsonResponseAsync(versionsResponse);                if (versionsJson.ValueKind != JsonValueKind.Array || versionsJson.GetArrayLength() == 0)            return; // Skip if no versions found        // Get first version ID        if (!versionsJson[0].TryGetProperty("versionId", out var versionIdElement))            return; // Skip if versionId not found        var versionId = Guid.Parse(versionIdElement.GetString()!);        // Step 3: Get specific version        var versionResponse = await GetWithRetryAsync(EhrClient, ApiEndpoints.Ehr.VersionById(ehrId, versionId));        Assert.True(            versionResponse.StatusCode == HttpStatusCode.OK || versionResponse.StatusCode == HttpStatusCode.NotFound,            $"Expected 200 or 404, got {versionResponse.StatusCode}");    }}
